/// <summary>
///    Extension class of form <c>SalesAgreement</c> datasource <c>SalesAgreementHeader</c>
/// </summary>
[ExtensionOf(formdatasourcestr(SalesAgreement, SalesAgreementHeader))]
final class ETG_SalesAgreementHeader_DS_Extension
{

}

Method.Source:
public int active()
{
    int                 ret;
    AgreementReference  agreementReference;
    boolean             isTPAgreement = false;
    boolean             isReleased    = true;
    FormDataSource      salesAgreementHeader_ds         = any2Object(this) as FormDataSource;
    formRun             formRun                         = salesAgreementHeader_ds.formRun();
    FormDataSource      salesAgreementHeaderDefault_ds  = formRun.dataSource(formDataSourceStr(SalesAgreement, SalesAgreementHeaderDefault)) as FormDataSource;
    FormDataSource      aline_ds                        = formRun.dataSource(formDataSourceStr(SalesAgreement, Aline)) as FormDataSource;
    FormDataSource      SalesAgreementTrade_ds          = formRun.dataSource(formDataSourceStr(SalesAgreement, ETG_SalesAgreementHeader)) as FormDataSource;
    FormDataSource      agreementHeaderDefault_ds       = formRun.dataSource(formDataSourceStr(SalesAgreement, AgreementHeaderDefault)) as FormDataSource;
    FormDataSource      qualityGrp_ds                   = formRun.dataSource(formDataSourceStr(SalesAgreement, ETG_AgreementLineQualityGrp)) as FormDataSource;
    FormDataSource      tmsSalesAgreement_ds            = formRun.dataSource(formDataSourceStr(SalesAgreement, TMSSalesAgreementHeader)) as FormDataSource;
    FormControl         buttoncontrol                   = this.formRun().design().controlName(formControlStr(SalesAgreement,ButtonReleaseOrderCreate));

    FormDataSource          aLineQtyCommitmentSales_ds   = formRun.dataSource(formDataSourceStr(SalesAgreement,ALine_AgreementLineQuantityCommitment )) as FormDataSource;
    FormDataSource          aLineVolCommitmentSales_ds   = formRun.dataSource(formDataSourceStr(SalesAgreement,ALine_AgreementLineVolumeCommitment  )) as FormDataSource;
    FormDataSource          agreementLineDefaultSales_ds = formRun.dataSource(formDataSourceStr(SalesAgreement, AgreementLineDefault)) as FormDataSource;
    FormDataSource          inventDimSales_ds            = formRun.dataSource(formDataSourceStr(SalesAgreement, InventDim)) as FormDataSource;

    SalesAgreementHeader    salesAgreementHeader = SalesAgreementHeader_ds.cursor();        

    ETG_Parameters          parameter            = ETG_Parameters::find();
    ETGCanadaParameters     canadaParamaters     = ETGCanadaParameters::find();

    ret = next active();

    if(ETGACFParameters::find().EnableAbruptTerminationAgreement == NoYes::Yes)
    {
        FormControl  buttoncontrolconfirmation = formRun.design().controlName(formControlStr(SalesAgreement, ButtonConfirmation));

        // NS DLT 28/05/2023 Shreelekha Check if workflow for this document is not active
        boolean isWorkflowActive = WorkflowTable::findActiveTemplate(workflowTypeStr(ETGSalesAgreementWFType)).RecId != 0;

        if (!isWorkflowActive)
        {
            // Set workflow status to Approved
            salesAgreementHeader.ETGWorkflowStatus = VersioningDocumentState::Approved;

            // Enable confirmation button
            buttoncontrolconfirmation.enabled(true);
        }
        // NE DLT 28/05/2023 Shreelekha Check if workflow for this document is not active

        if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated || salesAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
        {
            buttoncontrol.enabled(false);
            buttoncontrolconfirmation.enabled(false);
        }
    }

    // NS DLT 28/05/2023 Shreelekha Check if workflow for this document is not active
    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        FormControl  buttoncontrolconfirmation = formRun.design().controlName(formControlStr(SalesAgreement, ButtonConfirmation));
        boolean      isWorkflowActive          = WorkflowTable::findActiveTemplate(workflowTypeStr(ETGSalesAgreementWFType)).RecId != 0;

        if (!isWorkflowActive)
        {
            // Set workflow status to Approved
            salesAgreementHeader.ETGWorkflowStatus = VersioningDocumentState::Approved;

            // Enable confirmation button
            buttoncontrolconfirmation.enabled(true);
        }
    }
    // NE DLT 28/05/2023 Shreelekha Check if workflow for this document is not active


    select firstonly agreementReference
        where agreementReference.DerivedAgreement == SalesAgreementHeader.RecId;

    if(SalesAgreementHeader.ETG_TradingStatusSales != ETG_TradingStatus::None)
    {
        isReleased = false;
    }

    if(parameter.ETG_FrozenValidations
        && parameter.ETG_FrozenValidationPurchaseAgreement
        && (SalesAgreementHeader.ETG_IsThirdParty || agreementReference))
    {
        isTPAgreement = true;
    }

    formRun.design().controlName(formcontrolstr(SalesAgreement,TabHeaderFinancialDimensions)).allowEdit(isReleased);
    formRun.design().controlName(formcontrolstr(SalesAgreement,ButtonConfirmationETG)).allowEdit(isReleased);
    tmsSalesAgreement_ds.allowEdit(isReleased);

    if(!isReleased)
    {
        SalesAgreementHeader_ds.allowEdit(true);//Abhinav - 12-02-2025
        salesAgreementHeaderDefault_ds.allowEdit(false);
        agreementHeaderDefault_ds.allowEdit(false);
        SalesAgreementTrade_ds.allowEdit(false);

        qualityGrp_ds.allowCreate(false);
        qualityGrp_ds.allowDelete(false);
        formRun.design().controlName(formcontrolstr(SalesAgreement,TabHeaderGeneral)).allowEdit(false);
        //CS, Abhinav
        formRun.design().controlName(formcontrolstr(SalesAgreement,LineViewHeader_AgreementState)).allowEdit(true);
        formRun.design().controlName(formcontrolstr(SalesAgreement,ETGReasonCode)).allowEdit(true);
        //CE

    }
    else if(isTPAgreement)
    {
        allowEditFieldGroup(SalesAgreementHeader_ds, tableFieldGroupStr(SalesAgreementHeader_ds, AgreementFieldsEditable));
        allowEditFieldGroup(SalesAgreementTrade_ds, tableFieldGroupStr(SalesAgreementTrade_ds, AgreementFieldsEditable));
        allowEditFieldGroup(agreementHeaderDefault_ds, tableFieldGroupStr(agreementHeaderDefault_ds, AgreementFieldsEditable));
        allowEditFieldGroup(salesAgreementHeaderDefault_ds, tableFieldGroupStr(salesAgreementHeaderDefault_ds, AgreementFieldsEditable));
        formRun.design().controlName(formcontrolstr(SalesAgreement,TabHeaderGeneral)).allowEdit(false);
        formRun.design().controlName(formcontrolstr(SalesAgreement,LineViewHeader)).allowEdit(false);
    }
    else
    {
        SalesAgreementHeader_ds.allowEdit(true);
        salesAgreementHeaderDefault_ds.allowEdit(true);
        agreementHeaderDefault_ds.allowEdit(true);
        SalesAgreementTrade_ds.allowEdit(true);

        qualityGrp_ds.allowCreate(true);
        qualityGrp_ds.allowDelete(true);
        formRun.design().controlName(formcontrolstr(SalesAgreement,LineViewHeader)).allowEdit(true);
        formRun.design().controlName(formcontrolstr(SalesAgreement,TabHeaderGeneral)).allowEdit(true);
    }
    //NS, DLT  5/15/2025 Disable ButtonConfirmation if workflow is Draft or InReview        
    if (ETGACFParameters::find().EnableSalesAgreementWorkflow == NoYes::Yes)
    {
        FormControl buttonConfirmation = formRun.design().controlName(formControlStr(SalesAgreement, ButtonConfirmationETG));

        if (salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Draft ||
            salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::InReview)
        {
            buttonConfirmation.enabled(false);
        }
        else if (salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Rejected)
        {
            buttonConfirmation.enabled(false);
            buttoncontrol.enabled(false);
        }
        else
        {
            buttonConfirmation.enabled(true);
        }
    }
    //NS, DLT  5/15/2025 Disable ButtonConfirmation if workflow is Draft or InReview


    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        if(salesAgreementHeader.AgreementState == AgreementState::OnHold)
        {
            element.design(ViewEditMode::Edit);
            SalesAgreementHeader_ds.allowEdit(true);
            salesAgreementHeaderDefault_ds.allowEdit(true);
            agreementHeaderDefault_ds.allowEdit(true);
            qualityGrp_ds.allowEdit(true);
            tmsSalesAgreement_ds.allowEdit(true);

            aline_ds.allowCreate(true);
            aline_ds.allowDelete(true);
            aline_ds.allowEdit(true);
            inventDimSales_ds.allowEdit(true);
            aLineQtyCommitmentSales_ds.allowEdit(true);
            aLineQtyCommitmentSales_ds.allowCreate(true);
            aLineQtyCommitmentSales_ds.allowDelete(true);
            agreementLineDefaultSales_ds.allowCreate(true);
            agreementLineDefaultSales_ds.allowEdit(true);
            agreementLineDefaultSales_ds.allowDelete(true);

            FormControl         LineViewLineDetailsctrl    = element.design().controlName('LineViewLineDetails');
            LineViewLineDetailsctrl.allowEdit(true);
            LineViewLineDetailsctrl.enabled(true);

            FormControl         OverDeliveryPctCtrl    = element.design().controlName('OverDeliveryPct');
            OverDeliveryPctCtrl.allowEdit(true);
            OverDeliveryPctCtrl.enabled(true);
            FormControl         UnderDeliveryPctCtrl    = element.design().controlName('UnderDeliveryPct');
            UnderDeliveryPctCtrl.allowEdit(true);
            UnderDeliveryPctCtrl.enabled(true);
        }
        else
        {
            element.design(ViewEditMode::View);
            SalesAgreementHeader_ds.allowEdit(false);
            salesAgreementHeaderDefault_ds.allowEdit(false);
            agreementHeaderDefault_ds.allowEdit(false);
            qualityGrp_ds.allowEdit(false);
            tmsSalesAgreement_ds.allowEdit(false);

            aline_ds.allowCreate(false);
            aline_ds.allowDelete(false);
            aline_ds.allowEdit(false);
            inventDimSales_ds.allowEdit(false);
            aLineQtyCommitmentSales_ds.allowEdit(false);
            aLineQtyCommitmentSales_ds.allowCreate(false);
            aLineQtyCommitmentSales_ds.allowDelete(false);
            agreementLineDefaultSales_ds.allowCreate(false);
            agreementLineDefaultSales_ds.allowEdit(false);
            agreementLineDefaultSales_ds.allowDelete(false);

            FormControl         LineViewLineDetailsctrl    = element.design().controlName('LineViewLineDetails');
            LineViewLineDetailsctrl.allowEdit(false);
            LineViewLineDetailsctrl.enabled(false);

            FormControl         OverDeliveryPctCtrl    = element.design().controlName('OverDeliveryPct');
            OverDeliveryPctCtrl.allowEdit(false);
            OverDeliveryPctCtrl.enabled(false);
            FormControl         UnderDeliveryPctCtrl    = element.design().controlName('UnderDeliveryPct');
            UnderDeliveryPctCtrl.allowEdit(false);
            UnderDeliveryPctCtrl.enabled(false);
        }
    }
    //NE, DLT ,27/05/2025 Shreelekha Line items should be enable when change request button is clicked

    //DMS Integration
    SalesAgreementHeader_ds.object(fieldNum(SalesAgreementHeader, ETGDMSDealNumber)).allowEdit(false);
    //DMS Integration

    //fields to be non-editable integrated from deal 
    if(canadaParamaters.DMSFieldFreezeDeal && salesAgreementHeader.ETGDMSDealNumber)
    {
        formRun.design().controlName(formControlStr(SalesAgreement, LineViewHeader_Currency)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, LineViewHeader_ExpirationDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, LineViewHeader_EffectiveDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, AgreementLine_AgreementLineQuantityCommitment_CommitedQuantity)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, AgreementLine_AgreementLineQuantityCommitment_ProductUnitOfMeasure)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, AgreementLine_AgreementLineQuantityCommitment_PricePerUnit)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, AgreementLine_ExpirationDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, ValidityPeriodLine_ExpirationDate)).allowEdit(false);
