        formRun.design().controlName(formControlStr(SalesAgreement, ALine_AgreementLineQuantityCommitment_ProductUnitOfMeasure)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, TabFinancialDimensions)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, TabLineDimension)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, TradingDetails)).allowEdit(false);
