        formRun.design().controlName(formControlStr(SalesAgreement, DefaultAgreementLineExpirationDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, DefaultAgreementLineEffectiveDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, Through)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, BrokerageCommissionType)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, BrokerageCommissionValue)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, ReferenceGroup)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, TabHeaderTerm)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, TabHeaderFinancialDimensions)).allowEdit(false);
        formRun.design().controlName(formControlStr(SalesAgreement, ETGCanadaDetails)).allowEdit(false);

