[FormControlEventHandler(formControlStr(SalesAgreement, LineViewHeader_AgreementState), FormControlEventType::Modified)]
public static void LineViewHeader_AgreementState_OnModified(FormControl sender, FormControlEventArgs e)
{

    if(ETGACFParameters::find().EnableAbruptTerminationAgreement == NoYes::Yes)
    {
        FormControl          buttoncontrol        = sender.formRun().design().controlName(formControlStr(SalesAgreement, ButtonReleaseOrderCreate));
        SalesAgreementHeader salesAgreementHeader = sender.formRun().dataSource().cursor();

        if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated || salesAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
        {
            //CS, DLT, Abhinav - 18-02-2025
            AgreementLine                           agreementLine, agreementLineCheck, agreementLineLoop;
            FormDataSource  agreementLine_ds   = sender.formRun().dataSource(formDataSourceStr(SalesAgreement,Aline))  as FormDataSource;
            agreementLine      = agreementLine_ds.cursor();
            AgreementLineQuantityCommitment qtyCommitmentLoc;
            MultiSelectionHelper helper = MultiSelectionHelper::construct();
            helper.parmDatasource(agreementLine_ds);
            agreementLineLoop = helper.getFirst();

            if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated)
            {
                while (agreementLineLoop.RecId != 0)
                {
                    while select qtyCommitmentLoc
                    where qtyCommitmentLoc.RecId == agreementLineLoop.RecId
                    {
                        if(qtyCommitmentLoc.isReleased())
                        {
                            throw error("Termination is not allowed. Contract is already released");
                        }
                    }

                    agreementLineLoop = helper.getNext();
                }
            }
            //CE - 18-02-2025

            // DMS Reverse intergreation

            if (ETGACFParameters::find().EnableDMSIntegration 
                && BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereSalesAgreementIntegrationEventClass)))
            {
                if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated)
                {
                    AgreementHeaderHistory       agreementHeaderHistory;
                    select firstonly agreementHeaderHistory
                          order by RecId desc
                            where agreementHeaderHistory.AgreementHeader == salesAgreementHeader.RecId;

                    str confirmationnumber  = strFmt("%1-%2", salesAgreementHeader.SalesNumberSequence, agreementHeaderHistory.ConfirmationNumber);
                    str formattedDateTime = DateTimeUtil::toStr(agreementHeaderHistory.CreatedDateTime);

                    ETGDMSRevereSalesAgreementIntegrationContract contract = new ETGDMSRevereSalesAgreementIntegrationContract();

                    contract.parmDealNumber(salesAgreementHeader.ETGDMSDealNumber);
                    contract.parmDataAreaId(curExt());
                    contract.parmOperationType("Termination");
                    contract.parmActivityName("Sales Agreement Termination");
                    contract.parmDocumentNumber(confirmationnumber);
                    contract.parmDocumentDate(formattedDateTime);
                    contract.parmActivityOwner(SalesAgreementHeader.CreatedBy);
                    contract.parmActivityRemarks(strFmt("The Sales agreement %1 is Terminated",salesAgreementHeader.SalesNumberSequence));


                    ETGDMSRevereSalesAgreementIntegrationEventClass eventClass = ETGDMSRevereSalesAgreementIntegrationEventClass::newFromContract(contract);
                    eventClass.send();
                }
                else if(salesAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
                {
                    AgreementHeaderHistory       agreementHeaderHistory;

                    select firstonly agreementHeaderHistory
                            order by RecId desc
                            where agreementHeaderHistory.AgreementHeader == salesAgreementHeader.RecId;

                    str confirmationnumber  = strFmt("%1-%2", salesAgreementHeader.SalesNumberSequence, agreementHeaderHistory.ConfirmationNumber);
                    str formattedDateTime = DateTimeUtil::toStr(agreementHeaderHistory.CreatedDateTime);


                    ETGDMSRevereSalesAgreementIntegrationContract contract = new ETGDMSRevereSalesAgreementIntegrationContract();

                    contract.parmDealNumber(salesAgreementHeader.ETGDMSDealNumber);
                    contract.parmDataAreaId(curExt());
                    contract.parmOperationType("Force Closure");
                    contract.parmActivityName("Sales Agreement Force Closure");
                    contract.parmDocumentNumber(confirmationnumber);
                    contract.parmDocumentDate(formattedDateTime);
                    contract.parmActivityOwner(SalesAgreementHeader.CreatedBy);
                    contract.parmActivityRemarks(strFmt("The Sales agreement  %1 is Force Closed.",salesAgreementHeader.SalesNumberSequence));

                    ETGDMSRevereSalesAgreementIntegrationEventClass eventClass = ETGDMSRevereSalesAgreementIntegrationEventClass::newFromContract(contract);
                    eventClass.send();
                }
            }
            // DMS Reverse intergreation


            salesAgreementHeader.ETGWorkflowStatus = VersioningDocumentState::Draft;
            Workflow::activateFromWorkflowType(workflowTypeStr(ETGSalesAgreementWFType), salesAgreementHeader.RecId, "", NoYes::No);//Abhinav 15-020-2025

            buttoncontrol.enabled(false);
        }
        else
        {
            buttoncontrol.enabled(true);
        }
    }

    if(ETGACFParameters::find().EnableSalesAgreementWorkflow == NoYes::Yes)
    {
        SalesAgreementHeader salesAgreementHeader = sender.formRun().dataSource().cursor();
        if(salesAgreementHeader.ETGWorkflowStatus != VersioningDocumentState::Approved)
        {
            sender.formRun().design().controlName(formcontrolstr(SalesAgreement, ButtonConfirmationETG)).allowEdit(false);
            sender.formRun().design().controlName(formcontrolstr(SalesAgreement, ButtonConfirmationETG)).enabled(false);
        }
    }

    ///CS, DLT, Abhinav 
    if(ETGACFParameters::find().EnableAbruptTerminationAgreement == NoYes::Yes)
    {
       // SalesAgreementHeader salesAgreementHeader = sender.formRun().dataSource().cursor();
       FormDataSource salesAgreementHeader_ds = sender.formRun().dataSource(formDataSourceStr(SalesAgreement, SalesAgreementHeader)) as FormDataSource;
        SalesAgreementHeader salesAgreementHeader = salesAgreementHeader_ds.cursor();


        if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated || salesAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
        {
            AgreementLine                           agreementLine,agreementLineCheck;
            FormDataSource  agreementLine_ds   = sender.formRun().dataSource(formDataSourceStr(SalesAgreement,Aline))  as FormDataSource;
            agreementLine                      = agreementLine_ds.cursor();

            AgreementLineQuantityCommitment qtyCommitment;

            //select sum(ETGRemainingQuantity) from qtyCommitment
            //    where qtyCommitment.RecId == agreementLine.RecId;

            real remainingQty;

            while select qtyCommitment
                where qtyCommitment.RecId == agreementLine.RecId
            {
                remainingQty += qtyCommitment.quantityRemainingRelease();
            }

            if(remainingQty == 0)
            {
                if(!Box::yesNo("@ETG_New:ETGTerminateAgreementRemain",dialogButton::No))
                {
                    throw Error("@ETG_New:ETGUpdateStateCancelled");
                }
            }

        }
    }
    //CE
}

/// <summary>
/// DMS reverse integration changes
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesAgreement, Status_AgreementState), FormControlEventType::Modified)]
public static void Status_AgreementState_OnModified(FormControl sender, FormControlEventArgs e)
{
    if (ETGACFParameters::find().EnableDMSIntegration
        && BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereSalesAgreementIntegrationEventClass)))
    {
        SalesAgreementHeader salesAgreementHeader = sender.formRun().dataSource().cursor();
        if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated)
        {
            AgreementHeaderHistory       agreementHeaderHistory;
            select firstonly agreementHeaderHistory
                order by RecId desc 
                where agreementHeaderHistory.AgreementHeader == salesAgreementHeader.RecId;

            str confirmationnumber  = strFmt("%1-%2", salesAgreementHeader.SalesNumberSequence, agreementHeaderHistory.ConfirmationNumber);

           // date    agrementdate  = DateTimeUtil::date(agreementHeaderHistory.CreatedDateTime);
            //str formattedDate    = date2str(agrementdate,123,DateDay::Digits2,DateSeparator::None,DateMonth::Digits2,DateSeparator::None,DateYear::Digits4);
            str formattedDateTime = DateTimeUtil::toStr(agreementHeaderHistory.CreatedDateTime);


            ETGDMSRevereSalesAgreementIntegrationContract contract = new ETGDMSRevereSalesAgreementIntegrationContract();

            contract.parmDealNumber(salesAgreementHeader.ETGDMSDealNumber);
            contract.parmDataAreaId(curExt());
            contract.parmOperationType("Termination");
            contract.parmActivityName("Sales Agreement Termination");
            contract.parmDocumentNumber(confirmationnumber);
            contract.parmDocumentDate(formattedDateTime);
            contract.parmActivityOwner(SalesAgreementHeader.CreatedBy);
            contract.parmActivityRemarks(strFmt("The Sales agreement %1 is Terminated",salesAgreementHeader.SalesNumberSequence));

            ETGDMSRevereSalesAgreementIntegrationEventClass eventClass = ETGDMSRevereSalesAgreementIntegrationEventClass::newFromContract(contract);
            eventClass.send();
        }
        else if(salesAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
        {
            AgreementHeaderHistory       agreementHeaderHistory;

            select firstonly agreementHeaderHistory
                order by RecId desc
                where agreementHeaderHistory.AgreementHeader == salesAgreementHeader.RecId;

            str confirmationnumber  = strFmt("%1-%2", salesAgreementHeader.SalesNumberSequence, agreementHeaderHistory.ConfirmationNumber);

            str formattedDateTime = DateTimeUtil::toStr(agreementHeaderHistory.CreatedDateTime);

            ETGDMSRevereSalesAgreementIntegrationContract contract = new ETGDMSRevereSalesAgreementIntegrationContract();

            contract.parmDealNumber(salesAgreementHeader.ETGDMSDealNumber);
            contract.parmDataAreaId(curExt());
            contract.parmOperationType("Force Closure");
            contract.parmActivityName("Sales Agreement Force Closure");
            contract.parmDocumentNumber(confirmationnumber);
            contract.parmDocumentDate(formattedDateTime);
            contract.parmActivityOwner(SalesAgreementHeader.CreatedBy);
            contract.parmActivityRemarks(strFmt("The Sales agreement  %1 is Force Closed.",salesAgreementHeader.SalesNumberSequence));

            ETGDMSRevereSalesAgreementIntegrationEventClass eventClass = ETGDMSRevereSalesAgreementIntegrationEventClass::newFromContract(contract);
            eventClass.send();
        }
    }
    // DMS Reverse intergreation

}

public void write()
{
    FormDataSource salesAgreementDS = this;
    salesAgreementDS.refresh();
    next write();
    salesAgreementDS.reread();
}
